// Threat Detection Logic
const items = $input.all();
const threats = [];

for (const item of items) {
  const data = item.json;

  // Check for failed login attempts (Brute Force)
  if (data.failed_logins && data.failed_logins > 10) {
    threats.push({
      severity: 'HIGH',
      type: 'Brute Force Attack',
      source: data.source_ip || 'Unknown',
      description: `${data.failed_logins} failed login attempts detected`,
      timestamp: new Date().toISOString(),
      action_required: 'Block IP and notify SOC'
    });
  }

  // Check for critical vulnerabilities
  if (data.vulnerabilities) {
    const criticalVulns = data.vulnerabilities.filter(v => v.severity === 'CRITICAL');
    if (criticalVulns.length > 0) {
      threats.push({
        severity: 'CRITICAL',
        type: 'Critical Vulnerability Detected',
        affected_systems: data.hostname || 'Multiple systems',
        description: `${criticalVulns.length} critical vulnerabilities found`,
        timestamp: new Date().toISOString(),
        action_required: 'Immediate patching required'
      });
    }
  }

  // Check for suspicious traffic patterns
  if (data.traffic_volume && data.traffic_volume > 10000) {
    threats.push({
      severity: 'MEDIUM',
      type: 'Suspicious Traffic Pattern',
      source: data.source_ip || 'Unknown',
      description: `Abnormal traffic volume: ${data.traffic_volume} requests`,
      timestamp: new Date().toISOString(),
      action_required: 'Investigate and monitor'
    });
  }

  // Check for malware signatures
  if (data.malware_detected === true) {
    threats.push({
      severity: 'CRITICAL',
      type: 'Malware Detection',
      affected_systems: data.hostname || 'Unknown',
      description: `Malware signature: ${data.malware_name || 'Unknown'}`,
      timestamp: new Date().toISOString(),
      action_required: 'Isolate system immediately'
    });
  }

  // Check threat intelligence matches
  if (data.ioc_match === true) {
    threats.push({
      severity: 'HIGH',
      type: 'IOC Match',
      indicator: data.indicator || 'Unknown',
      description: `Known threat indicator detected: ${data.indicator_type}`,
      timestamp: new Date().toISOString(),
      action_required: 'Block and investigate'
    });
  }
}

return threats.map(threat => ({ json: threat }));

