parameters.jsCode:
// Generate Summary Report
const items = $input.all();

const summary = {
  timestamp: new Date().toISOString(),
  total_threats: items.length,
  critical: items.filter(i => i.json.severity === 'CRITICAL').length,
  high: items.filter(i => i.json.severity === 'HIGH').length,
  medium: items.filter(i => i.json.severity === 'MEDIUM').length,
  low: items.filter(i => i.json.severity === 'LOW').length,
  threat_types: [...new Set(items.map(i => i.json.type))],
  status: 'Workflow completed successfully'
};

return [{ json: summary }];

